scripts.script:
def jar = new File('${project.build.directory}/${glassfish.home}/glassfish/modules/jakarta.faces.jar').toPath()
def zipfs = java.nio.file.FileSystems.newFileSystem(jar, [:])
try {
    ['META-INF/services/jakarta.enterprise.inject.spi.Extension',
     'META-INF/services/jakarta.servlet.ServletContainerInitializer'].each { entry ->
        java.nio.file.Files.deleteIfExists(zipfs.getPath(entry))
    }
} finally {
    zipfs.close()
}

